import{j as a,c as o,b as t,ah as i}from"./chunks/framework.Br27zpCu.js";const d=JSON.parse('{"title":"How to Set Up Google Play","description":"","frontmatter":{},"headers":[],"relativePath":"bagisto-native/native-integration/android/how-to-guides/google-play-setup.md","filePath":"bagisto-native/native-integration/android/how-to-guides/google-play-setup.md","lastUpdated":1773762018000}'),l={name:"bagisto-native/native-integration/android/how-to-guides/google-play-setup.md"};function r(n,e,p,s,g,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="how-to-set-up-google-play" tabindex="-1">How to Set Up Google Play <a class="header-anchor" href="#how-to-set-up-google-play" aria-label="Permalink to &quot;How to Set Up Google Play&quot;">​</a></h1><p>This guide explains how to set up your Google Play Developer account for publishing your app.</p><h2 id="step-1-create-developer-account" tabindex="-1">Step 1: Create Developer Account <a class="header-anchor" href="#step-1-create-developer-account" aria-label="Permalink to &quot;Step 1: Create Developer Account&quot;">​</a></h2><ol><li>Visit the <a href="https://play.google.com/console" target="_blank" rel="noreferrer">Google Play Console</a>.</li><li>Click <strong>Start your profile</strong>.</li><li>Pay the one-time registration fee ($25 USD).</li><li>Complete your developer profile.</li></ol><h2 id="step-2-prepare-app-information" tabindex="-1">Step 2: Prepare App Information <a class="header-anchor" href="#step-2-prepare-app-information" aria-label="Permalink to &quot;Step 2: Prepare App Information&quot;">​</a></h2><p>You&#39;ll need to provide:</p><ul><li><strong>App Name</strong>: Your app&#39;s display name</li><li><strong>Short Description</strong>: Feature highlight (80 characters)</li><li><strong>Full Description</strong>: Detailed description (4000 characters)</li><li><strong>Screenshots</strong>: At least 2 screenshots (1080x1920)</li><li><strong>Feature Graphic</strong>: 1024x500 image</li><li><strong>App Icon</strong>: 512x512 PNG</li></ul><h2 id="step-3-configure-app" tabindex="-1">Step 3: Configure App <a class="header-anchor" href="#step-3-configure-app" aria-label="Permalink to &quot;Step 3: Configure App&quot;">​</a></h2><h3 id="app-categories" tabindex="-1">App Categories <a class="header-anchor" href="#app-categories" aria-label="Permalink to &quot;App Categories&quot;">​</a></h3><p>Choose appropriate categories:</p><ul><li><strong>Shopping</strong> (for e-commerce apps)</li><li>Or relevant category for your app</li></ul><h3 id="content-rating" tabindex="-1">Content Rating <a class="header-anchor" href="#content-rating" aria-label="Permalink to &quot;Content Rating&quot;">​</a></h3><p>Complete the content rating questionnaire honestly.</p><h3 id="pricing-distribution" tabindex="-1">Pricing &amp; Distribution <a class="header-anchor" href="#pricing-distribution" aria-label="Permalink to &quot;Pricing &amp; Distribution&quot;">​</a></h3><ul><li>Choose <strong>Free</strong> or <strong>Paid</strong></li><li>Select countries for distribution</li></ul><h2 id="step-4-app-signing" tabindex="-1">Step 4: App Signing <a class="header-anchor" href="#step-4-app-signing" aria-label="Permalink to &quot;Step 4: App Signing&quot;">​</a></h2><h3 id="option-1-app-signing-by-google-play-recommended" tabindex="-1">Option 1: App Signing by Google Play (Recommended) <a class="header-anchor" href="#option-1-app-signing-by-google-play-recommended" aria-label="Permalink to &quot;Option 1: App Signing by Google Play (Recommended)&quot;">​</a></h3><p>Google manages your app signing:</p><ol><li>Export a signing key from Android Studio</li><li>Upload it to Play Console</li><li>Google re-signs your app for distribution</li></ol><h3 id="option-2-self-managed" tabindex="-1">Option 2: Self-Managed <a class="header-anchor" href="#option-2-self-managed" aria-label="Permalink to &quot;Option 2: Self-Managed&quot;">​</a></h3><p>Keep your own signing key:</p><ol><li>Use the same key for all updates</li><li>Securely store the keystore</li></ol><h2 id="step-5-create-release" tabindex="-1">Step 5: Create Release <a class="header-anchor" href="#step-5-create-release" aria-label="Permalink to &quot;Step 5: Create Release&quot;">​</a></h2><ol><li>Go to <strong>Release → Production</strong></li><li>Upload your APK/AAB</li><li>Add release notes</li><li>Click <strong>Start Rollout</strong></li></ol><h2 id="step-6-wait-for-review" tabindex="-1">Step 6: Wait for Review <a class="header-anchor" href="#step-6-wait-for-review" aria-label="Permalink to &quot;Step 6: Wait for Review&quot;">​</a></h2><p>Google typically reviews within 24-72 hours.</p><h2 id="pre-launch-checklist" tabindex="-1">Pre-Launch Checklist <a class="header-anchor" href="#pre-launch-checklist" aria-label="Permalink to &quot;Pre-Launch Checklist&quot;">​</a></h2><ul><li>[ ] App icon uploaded</li><li>[ ] Screenshots uploaded</li><li>[ ] Privacy policy URL added</li><li>[ ] Content rating completed</li><li>[ ] Tested on multiple devices</li><li>[ ] Release APK built successfully</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./publish-to-play-store">Publish to Play Store</a> - Submit your app</li><li><a href="./build-release-apk">Build Release APK</a> - Prepare the build</li></ul>',30)])])}const u=a(l,[["render",r]]);export{d as __pageData,u as default};
